const c = (context.get('c') || 0) + 1;
context.set('c', c);
// every ~10th cycle the vibration channel degrades
const vibBad = c % 10 === 0;
msg.payload = {
    temp: {
        value: +(68 + (Math.random() - 0.5) * 2).toFixed(2),
        zScore: +(Math.random() * 1.2).toFixed(2),
        isAnomaly: false
    },
    vibration: {
        value: +(2.2 + (vibBad ? 3.5 : 0) + (Math.random() - 0.5) * 0.4).toFixed(2),
        zScore: vibBad ? 3.4 : +(Math.random() * 1.5).toFixed(2),
        isAnomaly: vibBad
    },
    pressure: {
        value: +(5.1 + (Math.random() - 0.5) * 0.1).toFixed(3),
        zScore: +(Math.random()).toFixed(2),
        isAnomaly: false
    }
};
msg.topic = 'machine-a/health';
return msg;
